import { Injectable } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import type { PaymentGatewayConfig } from "./dk-gateway/payment-gateway-config.interface.ts";

@Injectable()
export class PaymentConfigService {
  constructor(private configService: ConfigService) {}

  getConfig(): PaymentGatewayConfig {
    return {
      baseUrl: this.configService.getOrThrow<string>("DK_BASE_URL"),
      apiKey: this.configService.getOrThrow<string>("DK_API_KEY"),
      username: this.configService.getOrThrow<string>("DK_USERNAME"),
      password: this.configService.getOrThrow<string>("DK_PASSWORD"),
      clientId: this.configService.getOrThrow<string>("DK_CLIENT_ID"),
      clientSecret: this.configService.getOrThrow<string>("DK_CLIENT_SECRET"),
      sourceApp: this.configService.getOrThrow<string>("DK_SOURCE_APP"),
      beneficiaryAccount: this.configService.getOrThrow<string>(
        "DK_BENEFICIARY_ACCOUNT",
      ),
      publicAccount: this.configService.getOrThrow<string>(
        "DK_PUBLIC_ACCOUNT_NO",
      ),
      bankCode: this.configService.getOrThrow<string>("DK_BANK_CODE"),
      beneficiaryName:
        this.configService.get<string>("DK_BENEFICIARY_NAME") || "Lucky Pem",
    };
  }

  get baseUrl(): string {
    return this.getConfig().baseUrl;
  }

  get apiKey(): string {
    return this.getConfig().apiKey;
  }

  get username(): string {
    return this.getConfig().username;
  }

  get password(): string {
    return this.getConfig().password;
  }

  get clientId(): string {
    return this.getConfig().clientId;
  }

  get clientSecret(): string {
    return this.getConfig().clientSecret;
  }

  get sourceApp(): string {
    return this.getConfig().sourceApp;
  }

  get beneficiaryAccount(): string {
    return this.getConfig().beneficiaryAccount;
  }

  get publicAccount(): string {
    return this.getConfig().publicAccount;
  }

  get bankCode(): string {
    return this.getConfig().bankCode;
  }
}
